"""Plain-text output renderer."""
from __future__ import annotations

from typing import Iterable

from ..parser import LogEntry


def to_text(entries: Iterable[LogEntry]) -> str:
    """Render entries as readable plain text, one entry per line."""
    lines = []
    for e in entries:
        lines.append(
            f'{e.timestamp.isoformat()}  {e.ip:>15}  {e.method:<6} {e.status} {e.url}'
        )
    return '\n'.join(lines)

"""Output formatters: JSON, CSV, plain text.

This package replaces the monolithic output.py module.
All public symbols are re-exported here for backward compatibility.
"""
from __future__ import annotations

from typing import Any

# Re-export the renderer functions
from .json_renderer import to_json
from .csv_renderer import to_csv
from .plain_renderer import to_text
from .legacy import format_legacy

__all__ = ["to_json", "to_csv", "to_text", "render_aggregate", "format_legacy"]


def render_aggregate(agg: Any, fmt: str = "text") -> str:
    """Render an aggregate result (Counter, dict, list) as text/json/csv."""
    if fmt == "text":
        if hasattr(agg, "items"):
            return '\n'.join(f"{k}\t{v}" for k, v in agg.items())
        return '\n'.join(f"{k}\t{v}" for k, v in agg)
    elif fmt == "json":
        if hasattr(agg, "items"):
            items = list(agg.items())
        else:
            items = list(agg)
        parts = [f'"{k}":{v}' for k, v in items]
        return '{' + ','.join(parts) + '}'
    else:
        raise ValueError(f"unknown format: {fmt}")
